// ─── STEP 1: Extract attachment binary from Gmail ───────────────────────────
// Handles both Gmail trigger (attachment binary on item) and Drive/Webhook.
// Normalises to: { binary: { data: <base64>, fileName: <string> } }

const items = $input.all();
const results = [];

for (const item of items) {
  // Gmail sends attachments as binary properties named attachment_0, attachment_1 …
  // Drive sends a single binary. Webhook sends multipart.

  const binaryKeys = Object.keys(item.binary || {});

  if (binaryKeys.length === 0) {
    // Drive trigger: file content may be in item.json.binaryData or needs a separate download
    // For Drive, n8n Download node is used upstream — skip if no binary
    continue;
  }

  for (const key of binaryKeys) {
    const bin = item.binary[key];
    if (!bin.fileName?.endsWith('.csv') && !bin.mimeType?.includes('csv')) continue;

    results.push({
      json: {
        source_file_name: bin.fileName || 'unknown.csv',
        trigger_source: 'gmail'
      },
      binary: {
        data: bin
      }
    });
  }
}

return results;

// ─── STEP 2: Compute SHA-256 hash of file contents ──────────────────────────
// Used for idempotency: same file re-sent = same hash = skipped.

const crypto = require('crypto');
const items = $input.all();
const results = [];

for (const item of items) {
  const binData = item.binary?.data;
  if (!binData) {
    results.push({ json: { ...item.json, _error: 'No binary data found' } });
    continue;
  }

  // n8n stores binary as base64 string
  const buffer = Buffer.from(binData.data, 'base64');
  const hash = crypto.createHash('sha256').update(buffer).digest('hex');

  results.push({
    json: {
      ...item.json,
      source_hash: hash,
      raw_csv_base64: binData.data
    },
    binary: item.binary
  });
}

return results;

// ─── STEP 3: Enrich rows with file metadata ─────────────────────────────────
// Spreadsheet node loses the parent item context; re-attach source metadata.
// This node uses $('Compute SHA-256 Hash').first() to grab the hash + filename.

const meta = $('Compute SHA-256 Hash').first().json;
const rows = $input.all();

return rows.map(row => ({
  json: {
    ...row.json,
    source_file_name: meta.source_file_name,
    source_hash: meta.source_hash
  }
}));

// ─── CONFIGURATION ───────────────────────────────────────────────────────────
// DRY_RUN: set to true to write to supplier_invoices_staging instead of
// supplier_invoices. No production data is touched in dry-run mode.
const DRY_RUN = false;

// ─── STEP 4: Row-wise Validation & Normalisation ─────────────────────────────
// Business rules:
//   R1. Required fields present.
//   R2. Math: amount_incl_vat = amount_excl_vat + vat  (±0.01 tolerance).
//   R3. VAT default 15% (South Africa) if no explicit rate; flag mismatch.
//   R4. invoice_date not in the future (Africa/Johannesburg, UTC+2).
// Rounding: Math.round(x * 100) / 100  — 2 decimal places.

const executionId = $execution.id || 'unknown';
const items = $input.all();
const results = [];

function nowJHB() {
  return new Date(Date.now() + 2 * 3600 * 1000);
}

function round2(n) {
  return Math.round(n * 100) / 100;
}

function parseDate(str) {
  if (!str) return null;
  const d = new Date(str + 'T00:00:00+02:00');
  return isNaN(d.getTime()) ? null : d;
}

for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];
  const r = item.json;
  const notes = [];
  let valid = true;

  // ── Map CSV columns → unified schema ──────────────────────────────────────
  const invoice_number   = (r.invoice_number  || '').toString().trim();
  const supplier_number  = (r.supplier_number || '').toString().trim();
  const supplier_name    = (r.supplier_name   || '').toString().trim();
  const department       = (r.department      || '').toString().trim();
  const invoice_date_raw = (r.invoice_date    || '').toString().trim();

  const amount_excl_raw  = (r.amount_excl || '').toString().replace(/[^\d.]/g, '');
  const vat_raw          = (r.vat         || '').toString().replace(/[^\d.]/g, '');
  const vat_rate_raw     = (r.vat_rate    || '').toString().replace(/[^\d.]/g, '');
  const amount_incl_raw  = (r.amount_incl || '').toString().replace(/[^\d.]/g, '');

  // ── R1: Required fields ────────────────────────────────────────────────────
  if (!invoice_number)   { notes.push('MISSING: invoice_number');  valid = false; }
  if (!supplier_number)  { notes.push('MISSING: supplier_number'); valid = false; }
  if (!supplier_name)    { notes.push('MISSING: supplier_name');   valid = false; }
  if (!department)       { notes.push('MISSING: department');      valid = false; }
  if (!invoice_date_raw) { notes.push('MISSING: invoice_date');    valid = false; }
  if (!amount_excl_raw)  { notes.push('MISSING: amount_excl');     valid = false; }

  // ── Parse numerics ─────────────────────────────────────────────────────────
  const amount_excl_vat = amount_excl_raw ? round2(parseFloat(amount_excl_raw)) : null;

  let vat = null;
  let vat_rate = vat_rate_raw ? parseFloat(vat_rate_raw) : null;

  if (vat_raw) {
    vat = round2(parseFloat(vat_raw));
    if (vat_rate !== null && amount_excl_vat !== null) {
      const derived_vat = round2(amount_excl_vat * vat_rate / 100);
      if (Math.abs(derived_vat - vat) > 0.01) {
        notes.push('VAT_MISMATCH: given vat=' + vat + ' but derived from rate ' + vat_rate + '% = ' + derived_vat);
        valid = false;
      }
    }
  } else if (vat_rate !== null && amount_excl_vat !== null) {
    vat = round2(amount_excl_vat * vat_rate / 100);
  } else if (amount_excl_vat !== null) {
    vat_rate = 15;
    vat = round2(amount_excl_vat * 0.15);
    notes.push('VAT_DEFAULTED: applied 15% ZA default rate');
  }

  if (vat === null) { notes.push('MISSING: vat (cannot compute)'); valid = false; }

  let amount_incl_vat = null;
  if (amount_incl_raw) {
    amount_incl_vat = round2(parseFloat(amount_incl_raw));
  } else if (amount_excl_vat !== null && vat !== null) {
    amount_incl_vat = round2(amount_excl_vat + vat);
  }

  if (amount_incl_vat === null) { notes.push('MISSING: amount_incl_vat (cannot compute)'); valid = false; }

  // ── R2: Math check ─────────────────────────────────────────────────────────
  if (amount_excl_vat !== null && vat !== null && amount_incl_vat !== null) {
    const expected = round2(amount_excl_vat + vat);
    if (Math.abs(expected - amount_incl_vat) > 0.01) {
      notes.push('MATH_ERROR: amount_excl_vat(' + amount_excl_vat + ') + vat(' + vat + ') = ' + expected + ', but amount_incl_vat = ' + amount_incl_vat);
      valid = false;
    }
  }

  // ── R4: Invoice date not in the future ─────────────────────────────────────
  const invoice_date = parseDate(invoice_date_raw);
  if (!invoice_date) {
    notes.push('INVALID_DATE: ' + invoice_date_raw + ' is not a valid date (expected YYYY-MM-DD)');
    valid = false;
  } else {
    const today = nowJHB();
    today.setHours(0, 0, 0, 0);
    if (invoice_date > today) {
      notes.push('FUTURE_DATE: invoice_date ' + invoice_date_raw + ' is in the future (JHB timezone)');
      valid = false;
    }
  }

  results.push({
    json: {
      invoice_number,
      supplier_number,
      supplier_name,
      department,
      amount_excl_vat,
      vat,
      amount_incl_vat,
      invoice_date: invoice_date ? invoice_date_raw : null,
      source_file_name: r.source_file_name || null,
      source_hash:      r.source_hash      || null,
      status: valid ? 'pending_insert' : 'failed',
      validation_notes: notes.length > 0 ? notes.join(' | ') : null,
      row_number: idx + 1,
      execution_id: executionId,
      _valid: valid,
      _dry_run: DRY_RUN
    }
  });
}

return results;

