const queryResults = $input.all();
const validatedItems = $('Validate & Normalise Rows').all();
const results = [];

for (let i = 0; i < queryResults.length; i++) {
  const isDuplicate = queryResults[i].json.is_duplicate === true || 
                      queryResults[i].json.is_duplicate === 'true';

  const originalData = validatedItems[i]?.json || {};

  results.push({
    json: {
      ...originalData,
      _is_duplicate: isDuplicate
    }
  });
}

return results;

return $input.all().map(item => ({
  json: {
    ...item.json,
    status: 'duplicate',
    validation_notes: 'Duplicate: (supplier_number, invoice_number) already exists in supplier_invoices'
  }
}));

const allItems = $input.all();
const executionId = $execution.id || 'unknown';

let inserted = 0;
let duplicates = 0;
let failed = 0;
const errors = [];

for (const item of allItems) {
  const s = item.json.status;
  if (s === 'inserted') {
    inserted++;
  } else if (s === 'duplicate') {
    duplicates++;
  } else if (s === 'failed') {
    failed++;
    errors.push({
      row_number: item.json.row_number || 'N/A',
      invoice_number: item.json.invoice_number || 'N/A',
      supplier_number: item.json.supplier_number || 'N/A',
      supplier_name: item.json.supplier_name || 'N/A',
      reason: item.json.validation_notes || 'Unknown error'
    });
  }
}

const processed = inserted + duplicates + failed;

let errorRowsHtml = '';
const errorSlice = errors.slice(0, 20);
for (const e of errorSlice) {
  errorRowsHtml += '<tr>';
  errorRowsHtml += '<td style="padding:4px 8px;border:1px solid #ddd;">' + e.row_number + '</td>';
  errorRowsHtml += '<td style="padding:4px 8px;border:1px solid #ddd;">' + e.invoice_number + '</td>';
  errorRowsHtml += '<td style="padding:4px 8px;border:1px solid #ddd;">' + e.supplier_number + '</td>';
  errorRowsHtml += '<td style="padding:4px 8px;border:1px solid #ddd;">' + e.supplier_name + '</td>';
  errorRowsHtml += '<td style="padding:4px 8px;border:1px solid #ddd;color:#c00;">' + e.reason + '</td>';
  errorRowsHtml += '</tr>';
}

let errorSection = '';
if (errors.length > 0) {
  errorSection = '<h3 style="color:#c00;">Failed Rows (' + errors.length + ')</h3>';
  errorSection += '<table style="border-collapse:collapse;font-size:13px;width:100%;">';
  errorSection += '<thead><tr style="background:#f5f5f5;">';
  errorSection += '<th style="padding:6px 8px;border:1px solid #ddd;text-align:left;">Row #</th>';
  errorSection += '<th style="padding:6px 8px;border:1px solid #ddd;text-align:left;">Invoice #</th>';
  errorSection += '<th style="padding:6px 8px;border:1px solid #ddd;text-align:left;">Supplier #</th>';
  errorSection += '<th style="padding:6px 8px;border:1px solid #ddd;text-align:left;">Supplier Name</th>';
  errorSection += '<th style="padding:6px 8px;border:1px solid #ddd;text-align:left;">Reason</th>';
  errorSection += '</tr></thead>';
  errorSection += '<tbody>' + errorRowsHtml + '</tbody></table>';
} else {
  errorSection = '<p style="color:green;">No failed rows.</p>';
}

const failedColor = failed > 0 ? '#c00' : 'green';

const emailBody = '<html><body style="font-family:Arial,sans-serif;color:#333;">'
  + '<h2>Supplier Invoice Ingest Summary</h2>'
  + '<table style="border-collapse:collapse;margin-bottom:16px;">'
  + '<tr><td style="padding:4px 12px 4px 0;"><strong>Processed</strong></td><td style="padding:4px;">' + processed + '</td></tr>'
  + '<tr><td style="padding:4px 12px 4px 0;"><strong>Inserted</strong></td><td style="padding:4px;color:green;">' + inserted + '</td></tr>'
  + '<tr><td style="padding:4px 12px 4px 0;"><strong>Duplicates</strong></td><td style="padding:4px;color:orange;">' + duplicates + '</td></tr>'
  + '<tr><td style="padding:4px 12px 4px 0;"><strong>Failed</strong></td><td style="padding:4px;color:' + failedColor + ';">' + failed + '</td></tr>'
  + '</table>'
  + errorSection
  + '<hr/>'
  + '<p style="font-size:11px;color:#999;">Execution ID: ' + executionId + ' &nbsp;|&nbsp; Generated by n8n &nbsp;|&nbsp; Africa/Johannesburg</p>'
  + '</body></html>';

const subject = 'Supplier Ingest: ' + inserted + ' ok, ' + duplicates + ' dup, ' + failed + ' failed';

return [{
  json: {
    processed: processed,
    inserted: inserted,
    duplicates: duplicates,
    failed: failed,
    errors: errors,
    execution_id: executionId,
    email_subject: subject,
    email_body_html: emailBody
  }
}];

// File already processed — build skip notification email
const hashNode = $('Compute SHA-256 Hash').first().json;
const fileName = hashNode.source_file_name || 'unknown file';
const hash = hashNode.source_hash || 'unknown';
const executionId = $execution.id || 'unknown';

return [{
