      + '<tr><td style="padding:4px 12px 4px 0;"><strong>File Name</strong></td><td>' + fileName + '</td></tr>'
      + '<tr><td style="padding:4px 12px 4px 0;"><strong>SHA-256 Hash</strong></td><td style="font-family:monospace;font-size:11px;">' + hash + '</td></tr>'
      + '<tr><td style="padding:4px 12px 4px 0;"><strong>Execution ID</strong></td><td>' + executionId + '</td></tr>'
      + '</table>'
      + '<p>No rows were inserted. If this is a new file, verify that the file contents are different from the previously processed version.</p>'
      + '<hr/><p style="font-size:11px;color:#999;">Generated by n8n · Supplier Invoice Ingest · Africa/Johannesburg</p>'
      + '</body></html>'
  }
}];

const item = $input.first();
return [{
